// Using let (can be reassigned)
let playerName = "Hero";
let playerLevel = 1;

// Using const (cannot be reassigned)
const GAME_TITLE = "Adventure Quest";
const MAX_LIVES = 3;

// Using var (old way, function-scoped)
var oldStyle = "avoid this";

// ❌ Bad - unclear purpose
let x = 5;
let d = 10;

// ✅ Good - clear purpose
let userAge = 25;
let daysUntilDeadline = 10;

// ❌ Bad - too verbose
let numberOfDaysUntilTheProjectDeadlineIsDue = 10;

// ✅ Good - just right
let daysUntilDeadline = 10;

